+  int getOem7MessageId(const std::string& msg_name)
+  {
+    return oem7_msg_id_map[msg_name];
+  }
+
+  const std::string& getOem7MessageName(int msg_id)
+  {
+    return oem7_msg_name_map[msg_id];
+  }
